#!/usr/bin/env python3
import argparse, subprocess, sys, tempfile, os, base64
from pathlib import Path

SH_SRC_B64 = ""
DH_SRC_B64 = ""

def parse_args():
    p = argparse.ArgumentParser(description='SO3 unified ILP (SH/DH)')
    p.add_argument('--cdl', required=True)
    p.add_argument('--cell', required=False)
    p.add_argument('--subckt', required=False)
    p.add_argument('--dummy-for-ideal', type=int, default=0)
    p.add_argument('--dummy-padding', type=int, default=0)
    p.add_argument('--misalign-col', type=int, default=0)
    p.add_argument('--out-cell-name', default=None)
    p.add_argument('--arch', choices=['SH','DH'], default='SH')
    p.add_argument('--mh-order', choices=['N_FIRST','P_FIRST'], default='N_FIRST')
    p.add_argument('--python', default=sys.executable)
    return p.parse_args()

def main():
    args = parse_args()
    cell = args.cell or args.subckt
    if not cell:
        raise SystemExit('ERROR: --cell is required (or use --subckt)')
    # Ensure imports like ilp_pnr_function work by running in src dir
    root = Path(__file__).resolve().parent
    proj_root = root.parent
    env = os.environ.copy()
    py_path = env.get("PYTHONPATH", "")
    if str(root) not in py_path.split(os.pathsep):
        env["PYTHONPATH"] = os.pathsep.join([p for p in [str(root), py_path] if p])
    # Ensure model dumps go under project root instead of /
    if not env.get("GUROBI_DUMP_MODEL"):
        dump_base = proj_root / "gurobi_dumps" / (args.out_cell_name or cell)
        env["GUROBI_DUMP_MODEL"] = str(dump_base)
    base_argv = [args.python, '', '--cdl', args.cdl, '--cell', cell,
                 '--dummy-for-ideal', str(args.dummy_for_ideal),
                 '--dummy-padding', str(args.dummy_padding),
                 '--misalign-col', str(args.misalign_col)]
    if args.out_cell_name:
        base_argv += ['--out-cell-name', args.out_cell_name]
    if args.arch == 'DH':
        base_argv += ['--mh-order', args.mh_order]
        src_b64 = DH_SRC_B64
    else:
        src_b64 = SH_SRC_B64
    code = base64.b64decode(src_b64)
    with tempfile.NamedTemporaryFile('wb', suffix='.py', delete=False) as tf:
        tf.write(code)
        temp_path = tf.name
    base_argv[1] = temp_path
    print('[RUN ILP EMBEDDED]', ' '.join(base_argv))
    try:
        # Run from project root so outputs (log, dumps, cell files) land there
        subprocess.run(base_argv, check=True, cwd=str(proj_root), env=env)
    finally:
        try:
            os.unlink(temp_path)
        except OSError:
            pass

if __name__ == '__main__':
    main()
